{"command":"$ErrorActionPreference = 'Stop'
$workspace = 'C:\Users\T\Desktop\PeeDom'
$codexHome = 'C:\Users\T\.codex'
$timestamp = Get-Date -Format 'yyyyMMdd-HHmmss'
$exportRoot = Join-Path $workspace 'thread_exports'
$stagingDir = Join-Path $env:TEMP ("peedom-codex-export-" + $timestamp)
$bundleDir = Join-Path $stagingDir 'peedom-codex-threads'
$transcriptsDir = Join-Path $bundleDir 'transcripts'
$zipPath = Join-Path $exportRoot ("peedom-codex-threads-" + $timestamp + '.zip')

New-Item -ItemType Directory -Path $exportRoot -Force | Out-Null
New-Item -ItemType Directory -Path $transcriptsDir -Force | Out-Null

$indexMap = @{}
$sessionIndexPath = Join-Path $codexHome 'session_index.jsonl'
if (Test-Path $sessionIndexPath) {
  Get-Content -LiteralPath $sessionIndexPath | ForEach-Object {
    if ([string]::IsNullOrWhiteSpace($_)) { return }
    try {
      $row = $_ | ConvertFrom-Json
      if ($row.id) {
        $indexMap[$row.id] = $row
      }
    } catch {}
  }
}

function Test-IsPeeDomCwd {
  param([string]$Cwd)
  if ([string]::IsNullOrWhiteSpace($Cwd)) { return $false }
  return ($Cwd -match '(?i)\\PeeDom(?:\\|$)')
}

$sourcePaths = @(
  (Join-Path $codexHome 'sessions'),
  (Join-Path $codexHome 'archived_sessions')
) | Where-Object { Test-Path $_ }

$matches = New-Object System.Collections.Generic.List[object]
Get-ChildItem -LiteralPath $sourcePaths -File -Recurse | ForEach-Object {
  $path = $_.FullName
  $firstLine = Get-Content -LiteralPath $path -TotalCount 1 -Encoding UTF8
  if ([string]::IsNullOrWhiteSpace($firstLine)) { return }
  try {
    $meta = $firstLine | ConvertFrom-Json
  } catch {
    return
  }
  if ($meta.type -ne 'session_meta') { return }
  $cwd = [string]$meta.payload.cwd
  if (-not (Test-IsPeeDomCwd $cwd)) { return }

  $sessionId = [string]$meta.payload.id
  $indexRow = if ($indexMap.ContainsKey($sessionId)) { $indexMap[$sessionId] } else { $null }
  $threadName = if ($indexRow -and $indexRow.thread_name) { [string]$indexRow.thread_name } else { '' }
  $updatedAt = if ($indexRow -and $indexRow.updated_at) { [string]$indexRow.updated_at } else { '' }
  $isArchived = ($path -like '*\\archived_sessions\\*')
  $relativeCopyName = if ($isArchived) {
    Join-Path 'archived' $_.Name
  } else {
    $rel = $path.Substring((Join-Path $codexHome 'sessions').Length).TrimStart('\\')
    Join-Path 'sessions' $rel
  }
  $destinationPath = Join-Path $transcriptsDir $relativeCopyName
  New-Item -ItemType Directory -Path (Split-Path -Parent $destinationPath) -Force | Out-Null
  Copy-Item -LiteralPath $path -Destination $destinationPath -Force

  $matches.Add([pscustomobject]@{
    session_id = $sessionId
    thread_name = $threadName
    updated_at = $updatedAt
    cwd = $cwd
    archived = $isArchived
    source_path = $path
    export_path = $destinationPath
  }) | Out-Null
}

$sortedMatches = $matches | Sort-Object updated_at, session_id
$manifestJsonPath = Join-Path $bundleDir 'manifest.json'
$manifestCsvPath = Join-Path $bundleDir 'manifest.csv'
$summaryPath = Join-Path $bundleDir 'README.txt'

$manifest = [pscustomobject]@{
  exported_at = (Get-Date).ToString('o')
  workspace = $workspace
  filter = 'session_meta.payload.cwd matches \\PeeDom(\\|$)'
  transcript_count = @($sortedMatches).Count
  transcripts = $sortedMatches
}
$manifest | ConvertTo-Json -Depth 5 | Set-Content -LiteralPath $manifestJsonPath -Encoding UTF8
$sortedMatches | Select-Object session_id, thread_name, updated_at, cwd, archived, source_path | Export-Csv -LiteralPath $manifestCsvPath -NoTypeInformation -Encoding UTF8
@(
  "PeeDom Codex thread export",
  "Exported at: $((Get-Date).ToString('o'))",
  "Workspace filter: session_meta.payload.cwd matches \\PeeDom(\\|$)",
  "Transcript count: $(@($sortedMatches).Count)",
  "",
  "Files:",
  "- manifest.json",
  "- manifest.csv",
  "- transcripts/"
) | Set-Content -LiteralPath $summaryPath -Encoding UTF8

if (Test-Path $zipPath) {
  Remove-Item -LiteralPath $zipPath -Force
}
Compress-Archive -Path (Join-Path $bundleDir '*') -DestinationPath $zipPath -Force

$zip = [System.IO.Compression.ZipFile]::OpenRead($zipPath)
try {
  $entryCount = $zip.Entries.Count
} finally {
  $zip.Dispose()
}

$zipItem = Get-Item -LiteralPath $zipPath
[pscustomobject]@{
  zip_path = $zipItem.FullName
  zip_size_bytes = $zipItem.Length
  transcript_count = @($sortedMatches).Count
  zip_entry_count = $entryCount
  staging_dir = $bundleDir
} | ConvertTo-Json -Depth 3","workdir":"C:\Users\T\Desktop\PeeDom","timeout_ms":120000}

